import redis

r = redis.Redis()

# Simple Python cache-aside decorator
from functools import wraps

def cache_aside(key_fn, ttl=60):
    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            key = key_fn(*args, **kwargs)
            cached = r.get(key)
            if cached:
                return json.loads(cached)
            val = fn(*args, **kwargs)
            if val is not None:
                r.setex(key, ttl, json.dumps(val))
            return val
        return wrapper
    return decorator

# Usage
@cache_aside(lambda user_id: f"user:{user_id}")
def fetch_user(user_id):
    # expensive DB call
    return db.get_user(user_id)
